const days = ['Minggu', 'Senin', 'Selasa', 'Rabu', 'Kamis', 'Jumat', 'Sabtu'];
const months = ['Januari', 'Februari', 'Maret', 'April', 'Mei', 'Juni', 'Juli', 'Agustus', 'September', 'Oktober', 'November', 'Desember'];

let calendar = "";
const today = new Date();

// Menggeser index hari agar Senin = 0 dan Minggu = 6 (Standar Kalender)
const currentDayOfWeek = today.getDay() === 0 ? 6 : today.getDay() - 1; 

// Menghitung berapa hari lagi menuju hari Senin (awal "Minggu Depan")
const daysUntilNextMonday = 6 - currentDayOfWeek + 1; 

for (let i = 0; i < 28; i++) {
  const d = new Date();
  d.setDate(today.getDate() + i);
  const dayName = days[d.getDay()];
  const dateStr = `${d.getDate()} ${months[d.getMonth()]} ${d.getFullYear()}`;

  // Hitung selisih "minggu kalender" berdasarkan hari Senin terdekat
  let weekOffset = 0;
  if (i >= daysUntilNextMonday) {
    weekOffset = Math.floor((i - daysUntilNextMonday) / 7) + 1;
  }

  // Menentukan keterangan tambahan (suffix)
  let suffix = "";
  if (i === 0) {
    suffix = " (Hari Ini)";
  } else if (i === 1) {
    suffix = " (Besok)";
  } else if (weekOffset === 0) {
    suffix = " (Minggu Ini)"; // Menangkap sisa hari sebelum Senin (seperti hari Minggu)
  } else if (weekOffset === 1) {
    suffix = " (Minggu Depan)"; // Berlaku untuk Senin - Minggu depan
  } else if (weekOffset === 2) {
    suffix = " (2 Minggu Lagi)";
  } else if (weekOffset === 3) {
    suffix = " (3 Minggu Lagi)";
  } else if (weekOffset === 4) {
    suffix = " (4 Minggu Lagi)";
  }

  calendar += `- ${dayName}, ${dateStr}${suffix}\n`;
}

return {
  calendar_context: calendar,
  current_day: days[today.getDay()],
  current_date: `${today.getDate()} ${months[today.getMonth()]} ${today.getFullYear()}`
};

