// Jika diawali 0 → ganti dengan 62
if (cleaned.startsWith('0')) {
  cleaned = '62' + cleaned.substring(1);
}

// Jika diawali 62 → biarkan
// Jika format lain → tetap pakai hasil cleaned

return [
  {
    json: {
      phone: cleaned
